INSERT INTO visas (id, country, country_code, visa_name, type, duration_days, renewable, family_friendly, cost_eur, processing_days, income_requirement, requirements, notes, best_for, city_slugs) VALUES ('v1', 'Portugal', 'PT', 'D7 Passive Income Visa', 'Residency', 365, true, true, 90, 60, 760, '{"Proof of passive income","Clean criminal record","Health insurance","Portuguese NIF"}', 'One of Europe''s most popular family visa routes. Leads to permanent residency after 5 years. Income requirement is per adult — add 50% for spouse, 30% per child.', 'Families with remote income or investments wanting a European base', '{"lisbon","porto"}') ON CONFLICT (id) DO UPDATE SET country=EXCLUDED.country, country_code=EXCLUDED.country_code, visa_name=EXCLUDED.visa_name, type=EXCLUDED.type, duration_days=EXCLUDED.duration_days, renewable=EXCLUDED.renewable, family_friendly=EXCLUDED.family_friendly, cost_eur=EXCLUDED.cost_eur, processing_days=EXCLUDED.processing_days, income_requirement=EXCLUDED.income_requirement, requirements=EXCLUDED.requirements, notes=EXCLUDED.notes, best_for=EXCLUDED.best_for, city_slugs=EXCLUDED.city_slugs;
INSERT INTO visas (id, country, country_code, visa_name, type, duration_days, renewable, family_friendly, cost_eur, processing_days, income_requirement, requirements, notes, best_for, city_slugs) VALUES ('v2', 'Portugal', 'PT', 'Digital Nomad Visa (D8)', 'Digital Nomad', 365, true, true, 75, 30, 3040, '{"Employment contract or freelance income proof","Income 4x Portuguese minimum wage","Health insurance"}', 'Newer visa option for remote workers. Higher income requirement than D7 but faster processing. Includes dependents.', 'Remote workers earning above €3K/month who want EU residency path', '{"lisbon","porto"}') ON CONFLICT (id) DO UPDATE SET country=EXCLUDED.country, country_code=EXCLUDED.country_code, visa_name=EXCLUDED.visa_name, type=EXCLUDED.type, duration_days=EXCLUDED.duration_days, renewable=EXCLUDED.renewable, family_friendly=EXCLUDED.family_friendly, cost_eur=EXCLUDED.cost_eur, processing_days=EXCLUDED.processing_days, income_requirement=EXCLUDED.income_requirement, requirements=EXCLUDED.requirements, notes=EXCLUDED.notes, best_for=EXCLUDED.best_for, city_slugs=EXCLUDED.city_slugs;
INSERT INTO visas (id, country, country_code, visa_name, type, duration_days, renewable, family_friendly, cost_eur, processing_days, income_requirement, requirements, notes, best_for, city_slugs) VALUES ('v3', 'Spain', 'ES', 'Digital Nomad Visa (Ley de Startups)', 'Digital Nomad', 365, true, true, 80, 20, 2520, '{"Remote work for non-Spanish company","No more than 20% income from Spanish clients","Health insurance","Clean criminal record"}', 'Spain''s new nomad visa launched 2023. Favorable tax regime (15% flat) for first 4 years. Family members included.', 'Families wanting Mediterranean lifestyle with tax advantages', '{"valencia","malaga","las-palmas"}') ON CONFLICT (id) DO UPDATE SET country=EXCLUDED.country, country_code=EXCLUDED.country_code, visa_name=EXCLUDED.visa_name, type=EXCLUDED.type, duration_days=EXCLUDED.duration_days, renewable=EXCLUDED.renewable, family_friendly=EXCLUDED.family_friendly, cost_eur=EXCLUDED.cost_eur, processing_days=EXCLUDED.processing_days, income_requirement=EXCLUDED.income_requirement, requirements=EXCLUDED.requirements, notes=EXCLUDED.notes, best_for=EXCLUDED.best_for, city_slugs=EXCLUDED.city_slugs;
INSERT INTO visas (id, country, country_code, visa_name, type, duration_days, renewable, family_friendly, cost_eur, processing_days, income_requirement, requirements, notes, best_for, city_slugs) VALUES ('v4', 'Spain', 'ES', 'Non-Lucrative Visa', 'Residency', 365, true, true, 80, 45, 2400, '{"Sufficient funds (€28K/year minimum)","No work for Spanish companies","Health insurance","Clean criminal record"}', 'Traditional route for families with savings or passive income. Cannot work for Spanish employers but remote work for foreign companies is a grey area.', 'Families with savings or passive income seeking Spanish residency', '{"valencia","malaga","las-palmas"}') ON CONFLICT (id) DO UPDATE SET country=EXCLUDED.country, country_code=EXCLUDED.country_code, visa_name=EXCLUDED.visa_name, type=EXCLUDED.type, duration_days=EXCLUDED.duration_days, renewable=EXCLUDED.renewable, family_friendly=EXCLUDED.family_friendly, cost_eur=EXCLUDED.cost_eur, processing_days=EXCLUDED.processing_days, income_requirement=EXCLUDED.income_requirement, requirements=EXCLUDED.requirements, notes=EXCLUDED.notes, best_for=EXCLUDED.best_for, city_slugs=EXCLUDED.city_slugs;
INSERT INTO visas (id, country, country_code, visa_name, type, duration_days, renewable, family_friendly, cost_eur, processing_days, income_requirement, requirements, notes, best_for, city_slugs) VALUES ('v5', 'Georgia', 'GE', 'Visa-Free Entry', 'Tourist', 365, false, true, 0, 0, 0, '{"Valid passport from eligible country"}', 'Georgia offers visa-free stays of up to 1 year for citizens of 95+ countries. No income proof, no application. Simply arrive. One of the easiest countries in the world for families.', 'Families wanting a low-cost, zero-bureaucracy base for up to a year', '{"tbilisi"}') ON CONFLICT (id) DO UPDATE SET country=EXCLUDED.country, country_code=EXCLUDED.country_code, visa_name=EXCLUDED.visa_name, type=EXCLUDED.type, duration_days=EXCLUDED.duration_days, renewable=EXCLUDED.renewable, family_friendly=EXCLUDED.family_friendly, cost_eur=EXCLUDED.cost_eur, processing_days=EXCLUDED.processing_days, income_requirement=EXCLUDED.income_requirement, requirements=EXCLUDED.requirements, notes=EXCLUDED.notes, best_for=EXCLUDED.best_for, city_slugs=EXCLUDED.city_slugs;
