INSERT INTO visas (id, country, country_code, visa_name, type, duration_days, renewable, family_friendly, cost_eur, processing_days, income_requirement, requirements, notes, best_for, city_slugs) VALUES ('v7', 'Thailand', 'TH', 'Education Visa (ED)', 'Student', 365, true, true, 70, 14, 0, '{"Enrollment in Thai language school or university","Proof of enrollment"}', 'Common route for families: enroll parent in language school, children get dependent visas. Affordable and straightforward.', 'Families on a budget wanting to stay in Thailand long-term', '{"chiang-mai"}') ON CONFLICT (id) DO UPDATE SET country=EXCLUDED.country, country_code=EXCLUDED.country_code, visa_name=EXCLUDED.visa_name, type=EXCLUDED.type, duration_days=EXCLUDED.duration_days, renewable=EXCLUDED.renewable, family_friendly=EXCLUDED.family_friendly, cost_eur=EXCLUDED.cost_eur, processing_days=EXCLUDED.processing_days, income_requirement=EXCLUDED.income_requirement, requirements=EXCLUDED.requirements, notes=EXCLUDED.notes, best_for=EXCLUDED.best_for, city_slugs=EXCLUDED.city_slugs;
