INSERT INTO visas (id, country, country_code, visa_name, type, duration_days, renewable, family_friendly, cost_eur, processing_days, income_requirement, requirements, notes, best_for, city_slugs) VALUES ('v10', 'Mexico', 'MX', 'Temporary Resident Visa', 'Residency', 1460, false, true, 35, 20, 2100, '{"Proof of income or savings","Bank statements (6 months)","Clean criminal record"}', '4-year temporary residency with no work restrictions. Can also qualify through savings ($31K+). Tourist visa (180 days) is visa-free for most nationalities.', 'Families wanting a long-term Mexico base without frequent border runs', '{"playa-del-carmen","oaxaca"}') ON CONFLICT (id) DO UPDATE SET country=EXCLUDED.country, country_code=EXCLUDED.country_code, visa_name=EXCLUDED.visa_name, type=EXCLUDED.type, duration_days=EXCLUDED.duration_days, renewable=EXCLUDED.renewable, family_friendly=EXCLUDED.family_friendly, cost_eur=EXCLUDED.cost_eur, processing_days=EXCLUDED.processing_days, income_requirement=EXCLUDED.income_requirement, requirements=EXCLUDED.requirements, notes=EXCLUDED.notes, best_for=EXCLUDED.best_for, city_slugs=EXCLUDED.city_slugs;
