INSERT INTO visas (id, country, country_code, visa_name, type, duration_days, renewable, family_friendly, cost_eur, processing_days, income_requirement, requirements, notes, best_for, city_slugs) VALUES ('v12', 'South Africa', 'ZA', 'Visitor Visa (Remote Work)', 'Tourist', 90, true, true, 0, 0, 0, '{"Valid passport","Return ticket","Proof of accommodation"}', '90-day visa-free for many nationalities. South Africa doesn''t have a specific nomad visa yet, but 90-day tourist stays work for shorter family stints. Extensions possible.', 'Families wanting a 1-3 month adventure base', '{"cape-town"}') ON CONFLICT (id) DO UPDATE SET country=EXCLUDED.country, country_code=EXCLUDED.country_code, visa_name=EXCLUDED.visa_name, type=EXCLUDED.type, duration_days=EXCLUDED.duration_days, renewable=EXCLUDED.renewable, family_friendly=EXCLUDED.family_friendly, cost_eur=EXCLUDED.cost_eur, processing_days=EXCLUDED.processing_days, income_requirement=EXCLUDED.income_requirement, requirements=EXCLUDED.requirements, notes=EXCLUDED.notes, best_for=EXCLUDED.best_for, city_slugs=EXCLUDED.city_slugs;
INSERT INTO visas (id, country, country_code, visa_name, type, duration_days, renewable, family_friendly, cost_eur, processing_days, income_requirement, requirements, notes, best_for, city_slugs) VALUES ('v13', 'Serbia', 'RS', 'Visa-Free Entry', 'Tourist', 90, false, true, 0, 0, 0, '{"Valid passport from eligible country"}', '90-day visa-free for most nationalities. Serbia is also working on a digital nomad visa. Easy border runs to neighboring countries reset the counter.', 'Families wanting an affordable European base for short stints', '{"belgrade"}') ON CONFLICT (id) DO UPDATE SET country=EXCLUDED.country, country_code=EXCLUDED.country_code, visa_name=EXCLUDED.visa_name, type=EXCLUDED.type, duration_days=EXCLUDED.duration_days, renewable=EXCLUDED.renewable, family_friendly=EXCLUDED.family_friendly, cost_eur=EXCLUDED.cost_eur, processing_days=EXCLUDED.processing_days, income_requirement=EXCLUDED.income_requirement, requirements=EXCLUDED.requirements, notes=EXCLUDED.notes, best_for=EXCLUDED.best_for, city_slugs=EXCLUDED.city_slugs;
INSERT INTO visas (id, country, country_code, visa_name, type, duration_days, renewable, family_friendly, cost_eur, processing_days, income_requirement, requirements, notes, best_for, city_slugs) VALUES ('v14', 'Malaysia', 'MY', 'DE Rantau (Digital Nomad Pass)', 'Digital Nomad', 365, true, true, 200, 14, 2000, '{"Remote work proof","$24K/year income","Health insurance","IT/digital sector employment"}', 'Malaysia''s digital nomad program targets tech workers but is broadly interpreted. Includes dependents. Excellent value for families.', 'Tech-sector families wanting affordable Asian base with great schools', '{"penang"}') ON CONFLICT (id) DO UPDATE SET country=EXCLUDED.country, country_code=EXCLUDED.country_code, visa_name=EXCLUDED.visa_name, type=EXCLUDED.type, duration_days=EXCLUDED.duration_days, renewable=EXCLUDED.renewable, family_friendly=EXCLUDED.family_friendly, cost_eur=EXCLUDED.cost_eur, processing_days=EXCLUDED.processing_days, income_requirement=EXCLUDED.income_requirement, requirements=EXCLUDED.requirements, notes=EXCLUDED.notes, best_for=EXCLUDED.best_for, city_slugs=EXCLUDED.city_slugs;
INSERT INTO visas (id, country, country_code, visa_name, type, duration_days, renewable, family_friendly, cost_eur, processing_days, income_requirement, requirements, notes, best_for, city_slugs) VALUES ('v15', 'Guatemala', 'GT', 'Tourist Visa (CA-4)', 'Tourist', 90, true, true, 0, 0, 0, '{"Valid passport"}', 'CA-4 agreement allows 90 days across Guatemala, Honduras, El Salvador, and Nicaragua. Easy to extend or reset. Residency options available through investment.', 'Families seeking short-term Central American immersion', '{"antigua-guatemala"}') ON CONFLICT (id) DO UPDATE SET country=EXCLUDED.country, country_code=EXCLUDED.country_code, visa_name=EXCLUDED.visa_name, type=EXCLUDED.type, duration_days=EXCLUDED.duration_days, renewable=EXCLUDED.renewable, family_friendly=EXCLUDED.family_friendly, cost_eur=EXCLUDED.cost_eur, processing_days=EXCLUDED.processing_days, income_requirement=EXCLUDED.income_requirement, requirements=EXCLUDED.requirements, notes=EXCLUDED.notes, best_for=EXCLUDED.best_for, city_slugs=EXCLUDED.city_slugs;
INSERT INTO homeschool_laws (country, country_code, status, summary, requirements, notes, popular_cities) VALUES ('Portugal', 'PT', 'Grey area', 'Homeschooling is technically legal but the process is bureaucratic and inconsistently enforced.', 'Must register with local school and follow Portuguese curriculum. Annual assessments required.', 'Many expat families homeschool without registering. The D7 visa does not require school enrollment proof. Worldschooling families generally operate in a grey area without issues.', '{"lisbon","porto","ericeira","nazare"}') ON CONFLICT (country_code) DO UPDATE SET status=EXCLUDED.status, summary=EXCLUDED.summary, requirements=EXCLUDED.requirements, notes=EXCLUDED.notes, popular_cities=EXCLUDED.popular_cities;
INSERT INTO homeschool_laws (country, country_code, status, summary, requirements, notes, popular_cities) VALUES ('Spain', 'ES', 'Legal with restrictions', 'Education is compulsory ages 6-16. Homeschooling is not explicitly legal but is tolerated in most regions.', 'Varies by autonomous community. Catalonia and Andalusia are most tolerant. Some regions require curriculum alignment.', 'Spain''s Digital Nomad Visa does not require school enrollment. International families rarely face enforcement. Valencia and Málaga have active homeschool communities.', '{"valencia","malaga","las-palmas"}') ON CONFLICT (country_code) DO UPDATE SET status=EXCLUDED.status, summary=EXCLUDED.summary, requirements=EXCLUDED.requirements, notes=EXCLUDED.notes, popular_cities=EXCLUDED.popular_cities;
INSERT INTO homeschool_laws (country, country_code, status, summary, requirements, notes, popular_cities) VALUES ('Thailand', 'TH', 'Grey area', 'Homeschooling is legal for Thai citizens with registration. Foreign families on tourist/education visas operate in a grey area.', 'Thai citizens must register with the Ministry of Education. Foreign families are not subject to Thai education law.', 'Chiang Mai has one of the world''s largest homeschool/worldschool family communities. No enforcement against foreign families.', '{"chiang-mai"}') ON CONFLICT (country_code) DO UPDATE SET status=EXCLUDED.status, summary=EXCLUDED.summary, requirements=EXCLUDED.requirements, notes=EXCLUDED.notes, popular_cities=EXCLUDED.popular_cities;
INSERT INTO homeschool_laws (country, country_code, status, summary, requirements, notes, popular_cities) VALUES ('Indonesia', 'ID', 'Grey area', 'Homeschooling is legal for Indonesian citizens. Foreign families are not subject to Indonesian education law.', 'Indonesian citizens must register. Foreign families operate outside the system.', 'Bali has a massive homeschool and alternative education scene. Green School and similar institutions blur the line between school and unschool.', '{"bali-canggu","ubud"}') ON CONFLICT (country_code) DO UPDATE SET status=EXCLUDED.status, summary=EXCLUDED.summary, requirements=EXCLUDED.requirements, notes=EXCLUDED.notes, popular_cities=EXCLUDED.popular_cities;
INSERT INTO homeschool_laws (country, country_code, status, summary, requirements, notes, popular_cities) VALUES ('Georgia', 'GE', 'Legal', 'Homeschooling is fully legal with minimal bureaucracy.', 'Register with the Ministry of Education. No curriculum requirements for foreign families.', 'Georgia''s 1-year visa-free policy makes it one of the easiest places to homeschool legally. Growing family community in Tbilisi.', '{"tbilisi"}') ON CONFLICT (country_code) DO UPDATE SET status=EXCLUDED.status, summary=EXCLUDED.summary, requirements=EXCLUDED.requirements, notes=EXCLUDED.notes, popular_cities=EXCLUDED.popular_cities;
INSERT INTO homeschool_laws (country, country_code, status, summary, requirements, notes, popular_cities) VALUES ('Colombia', 'CO', 'Legal', 'Homeschooling is legal and constitutionally protected.', 'No registration required. Families have full autonomy over curriculum.', 'Colombia''s digital nomad visa includes dependents. Medellín and Bogotá have active homeschool co-ops.', '{"medellin","bogota"}') ON CONFLICT (country_code) DO UPDATE SET status=EXCLUDED.status, summary=EXCLUDED.summary, requirements=EXCLUDED.requirements, notes=EXCLUDED.notes, popular_cities=EXCLUDED.popular_cities;
INSERT INTO homeschool_laws (country, country_code, status, summary, requirements, notes, popular_cities) VALUES ('Mexico', 'MX', 'Legal', 'Homeschooling is legal. Education is compulsory but can be fulfilled at home.', 'No formal registration. SEP (education ministry) provides free curriculum materials.', 'Mexico is one of the most homeschool-friendly countries in Latin America. Large worldschool communities in Oaxaca and Playa del Carmen.', '{"playa-del-carmen","oaxaca"}') ON CONFLICT (country_code) DO UPDATE SET status=EXCLUDED.status, summary=EXCLUDED.summary, requirements=EXCLUDED.requirements, notes=EXCLUDED.notes, popular_cities=EXCLUDED.popular_cities;
INSERT INTO homeschool_laws (country, country_code, status, summary, requirements, notes, popular_cities) VALUES ('Hungary', 'HU', 'Legal with restrictions', 'Homeschooling is legal but requires approval from the local government.', 'Must apply to the local education authority. Annual exams required. Curriculum must align with national standards.', 'Budapest has several international schools as alternatives. The approval process can be lengthy for non-Hungarian speakers.', '{"budapest"}') ON CONFLICT (country_code) DO UPDATE SET status=EXCLUDED.status, summary=EXCLUDED.summary, requirements=EXCLUDED.requirements, notes=EXCLUDED.notes, popular_cities=EXCLUDED.popular_cities;
INSERT INTO homeschool_laws (country, country_code, status, summary, requirements, notes, popular_cities) VALUES ('South Africa', 'ZA', 'Legal', 'Homeschooling is legal and well-established with a strong community.', 'Must register with the provincial education department. Parents must have at least a matric (Grade 12) qualification.', 'South Africa has one of Africa''s most developed homeschool ecosystems. Multiple curricula available including Cambridge and IEB.', '{"cape-town"}') ON CONFLICT (country_code) DO UPDATE SET status=EXCLUDED.status, summary=EXCLUDED.summary, requirements=EXCLUDED.requirements, notes=EXCLUDED.notes, popular_cities=EXCLUDED.popular_cities;
INSERT INTO homeschool_laws (country, country_code, status, summary, requirements, notes, popular_cities) VALUES ('Malaysia', 'MY', 'Legal', 'Homeschooling is legal and growing rapidly.', 'Must register with the Ministry of Education. Foreign families on MM2H or similar visas can homeschool freely.', 'Penang has a strong English-speaking homeschool community. Many families combine homeschool with part-time international school enrollment.', '{"penang"}') ON CONFLICT (country_code) DO UPDATE SET status=EXCLUDED.status, summary=EXCLUDED.summary, requirements=EXCLUDED.requirements, notes=EXCLUDED.notes, popular_cities=EXCLUDED.popular_cities;
INSERT INTO homeschool_laws (country, country_code, status, summary, requirements, notes, popular_cities) VALUES ('Japan', 'JP', 'Grey area', 'School attendance is compulsory for Japanese citizens ages 6-15. Foreign residents are not legally required to attend school.', 'Japanese citizens must enroll. Foreign families can choose to homeschool without penalty.', 'The system is strict for Japanese families but accommodating of foreigners. International schools in Kyoto and Tokyo are alternatives.', '{"kyoto"}') ON CONFLICT (country_code) DO UPDATE SET status=EXCLUDED.status, summary=EXCLUDED.summary, requirements=EXCLUDED.requirements, notes=EXCLUDED.notes, popular_cities=EXCLUDED.popular_cities;
INSERT INTO homeschool_laws (country, country_code, status, summary, requirements, notes, popular_cities) VALUES ('Romania', 'RO', 'Legal', 'Homeschooling has been legal since 2020 with registration.', 'Must register with the school inspectorate. Annual evaluations required.', 'A recent legal change made Romania more accessible for homeschooling families. Bucharest has growing expat interest.', '{"bucharest"}') ON CONFLICT (country_code) DO UPDATE SET status=EXCLUDED.status, summary=EXCLUDED.summary, requirements=EXCLUDED.requirements, notes=EXCLUDED.notes, popular_cities=EXCLUDED.popular_cities;
INSERT INTO homeschool_laws (country, country_code, status, summary, requirements, notes, popular_cities) VALUES ('Brazil', 'BR', 'Legal with restrictions', 'Homeschooling was legalized in 2024 after years of legal ambiguity.', 'Must register with the local education secretariat. Annual assessments aligned with national curriculum.', 'Implementation varies by state. Florianópolis and Porto Alegre have active alternative education communities.', '{"florianopolis","porto-alegre"}') ON CONFLICT (country_code) DO UPDATE SET status=EXCLUDED.status, summary=EXCLUDED.summary, requirements=EXCLUDED.requirements, notes=EXCLUDED.notes, popular_cities=EXCLUDED.popular_cities;
INSERT INTO homeschool_laws (country, country_code, status, summary, requirements, notes, popular_cities) VALUES ('Costa Rica', 'CR', 'Legal', 'Homeschooling is legal. Education is compulsory but method is flexible.', 'No formal registration for homeschooling. MEP (education ministry) provides curriculum guidelines.', 'Santa Teresa and the Pacific coast have established surf-and-homeschool family communities.', '{"santa-teresa"}') ON CONFLICT (country_code) DO UPDATE SET status=EXCLUDED.status, summary=EXCLUDED.summary, requirements=EXCLUDED.requirements, notes=EXCLUDED.notes, popular_cities=EXCLUDED.popular_cities;
INSERT INTO homeschool_laws (country, country_code, status, summary, requirements, notes, popular_cities) VALUES ('Guatemala', 'GT', 'Legal', 'Homeschooling is legal with minimal oversight.', 'No registration required for foreign families. Guatemalan families must register with MINEDUC.', 'Antigua has one of Central America''s strongest expat homeschool communities. Spanish immersion is a major draw.', '{"antigua-guatemala"}') ON CONFLICT (country_code) DO UPDATE SET status=EXCLUDED.status, summary=EXCLUDED.summary, requirements=EXCLUDED.requirements, notes=EXCLUDED.notes, popular_cities=EXCLUDED.popular_cities;
INSERT INTO homeschool_laws (country, country_code, status, summary, requirements, notes, popular_cities) VALUES ('Serbia', 'RS', 'Grey area', 'Education is compulsory ages 6-15. Homeschooling is not explicitly addressed in law.', 'No formal process exists. Foreign families typically operate outside the system.', 'Belgrade''s growing digital nomad community includes homeschooling families. No known enforcement against foreign families.', '{"belgrade"}') ON CONFLICT (country_code) DO UPDATE SET status=EXCLUDED.status, summary=EXCLUDED.summary, requirements=EXCLUDED.requirements, notes=EXCLUDED.notes, popular_cities=EXCLUDED.popular_cities;
INSERT INTO homeschool_laws (country, country_code, status, summary, requirements, notes, popular_cities) VALUES ('Montenegro', 'ME', 'Grey area', 'Similar to Serbia — compulsory education law exists but homeschooling is not addressed.', 'No formal process. Foreign families operate without registration.', 'Kotor attracts families for short stays. No known issues with homeschooling.', '{"kotor"}') ON CONFLICT (country_code) DO UPDATE SET status=EXCLUDED.status, summary=EXCLUDED.summary, requirements=EXCLUDED.requirements, notes=EXCLUDED.notes, popular_cities=EXCLUDED.popular_cities;
INSERT INTO homeschool_laws (country, country_code, status, summary, requirements, notes, popular_cities) VALUES ('Greece', 'GR', 'Legal with restrictions', 'Homeschooling is technically possible but requires significant bureaucratic effort.', 'Must petition the local education authority. Approval is granted on a case-by-case basis.', 'Most island families (Lefkada etc.) homeschool informally. Enforcement is minimal outside Athens.', '{"lefkada"}') ON CONFLICT (country_code) DO UPDATE SET status=EXCLUDED.status, summary=EXCLUDED.summary, requirements=EXCLUDED.requirements, notes=EXCLUDED.notes, popular_cities=EXCLUDED.popular_cities;
INSERT INTO homeschool_laws (country, country_code, status, summary, requirements, notes, popular_cities) VALUES ('Bulgaria', 'BG', 'Legal', 'Homeschooling (independent learning) is legal since 2016.', 'Must register with a school that oversees the homeschooling. Annual exams required.', 'Bansko''s nomad community includes many homeschooling families. Low cost makes it attractive for long stays.', '{"bansko"}') ON CONFLICT (country_code) DO UPDATE SET status=EXCLUDED.status, summary=EXCLUDED.summary, requirements=EXCLUDED.requirements, notes=EXCLUDED.notes, popular_cities=EXCLUDED.popular_cities;
INSERT INTO homeschool_laws (country, country_code, status, summary, requirements, notes, popular_cities) VALUES ('Ecuador', 'EC', 'Legal', 'Homeschooling is legal and recognized by the Ministry of Education.', 'Must register with the local education office. Flexible on curriculum.', 'Ecuador''s low cost of living and visa-friendly policies make it attractive. Montañita is very informal.', '{"montanita"}') ON CONFLICT (country_code) DO UPDATE SET status=EXCLUDED.status, summary=EXCLUDED.summary, requirements=EXCLUDED.requirements, notes=EXCLUDED.notes, popular_cities=EXCLUDED.popular_cities;
INSERT INTO homeschool_laws (country, country_code, status, summary, requirements, notes, popular_cities) VALUES ('Bosnia and Herzegovina', 'BA', 'Grey area', 'Education is compulsory but homeschooling is not explicitly regulated.', 'No formal process exists for homeschooling.', 'Sarajevo has a small but growing international family presence. No enforcement against foreign families.', '{"sarajevo"}') ON CONFLICT (country_code) DO UPDATE SET status=EXCLUDED.status, summary=EXCLUDED.summary, requirements=EXCLUDED.requirements, notes=EXCLUDED.notes, popular_cities=EXCLUDED.popular_cities;
